class MyClass {
private:
 int* data;
 int size;
public:
 MyClass(int s) : size(s) {
 data = new int[size];
 }
 // Default assignment operator (shallow copy)
 MyClass& operator=(const MyClass& obj) {
 if (this == &obj) return *this; // Self-assignment check
 size = obj.size;
 data = obj.data; // Copies pointer address, not data!
 return *this;
 }
 ~MyClass() { delete[] data; }
};

class MyClass {
private:
 int* data;
 int size;
public:
 MyClass(int s) : size(s) {
 data = new int[size];
 }
 // Deep copy assignment operator
 MyClass& operator=(const MyClass& obj) {
 if (this == &obj) return *this; // Self-assignment check

 delete[] data; // Free old memory

 size = obj.size;
 data = new int[size]; // Allocate new memory
 for(int i = 0; i < size; i++) {
 data[i] = obj.data[i]; // Copy actual data
 }
 return *this;
 }
 ~MyClass() { delete[] data; }
};

class Box {
 int value;
public:
 Box(int v = 0) : value(v) {}

 // Copy constructor
 Box(const Box& b) : value(b.value) {
 std::cout << "Copy Constructor\n";
 }

 // Assignment operator
 Box& operator=(const Box& b) {
 value = b.value;
 std::cout << "Assignment Operator\n";
 return *this;
 }
};

int main() {
 Box a(5); // Constructor
 Box b = a; // Copy Constructor (initialization)
 Box c(10); // Constructor
 c = a; // Assignment Operator
 return 0;
}

class MyString {
 char* str;
 size_t len;
public:
 // Constructor
 MyString(const char* s = "") {
 len = strlen(s);
 str = new char[len + 1];
 strcpy(str, s);
 }

 // Destructor
 ~MyString() { delete[] str; }

 // Copy Constructor (deep)
 MyString(const MyString& obj) : len(obj.len) {
 str = new char[len + 1];
 strcpy(str, obj.str);
 }

 // Move Constructor
 MyString(MyString&& obj) noexcept : str(obj.str), len(obj.len) {
 obj.str = nullptr;
 obj.len = 0;
 }

 // Copy Assignment
 MyString& operator=(const MyString& obj) {
 if (this != &obj) {
 delete[] str;
 len = obj.len;
 str = new char[len + 1];
 strcpy(str, obj.str);
 }
 return *this;
 }

 // Move Assignment
 MyString& operator=(MyString&& obj) noexcept {
 if (this != &obj) {
 delete[] str;
 str = obj.str;
 len = obj.len;
 obj.str = nullptr;
 obj.len = 0;
 }
 return *this;
 }
};

class Array {
 int* arr;
 int size;
public:
 Array(int s) : size(s) {
 arr = new int[size];
 }

 Array& operator=(const Array& obj) {
 // Self-assignment check - critical!
 if (this == &obj) return *this;

 // Without check: delete arr first, then try to copy from deleted memory!
 delete[] arr; // Free existing memory

 size = obj.size;
 arr = new int[size];
 for(int i = 0; i < size; i++)
 arr[i] = obj.arr[i];

 return *this;
 }

 ~Array() { delete[] arr; }
};
